content.content:
775	  const Fs=[r.Fbrk,r.Fstr,r.FbA,r.FbB],descs=[`Su ${r.gr.Su}×As ${r.b.As}`,`τ ${r.threadTau} MPa (${r.hasNut?'ナット':'部材B'})`,`面圧 ${r.bA} MPa`,`面圧 ${r.bB} MPa`];
776	  ['bd0','bd1','bd2','bd3'].forEach((id,i)=>{const isL=Math.abs(Fs[i]-r.Flim)<0.01;ge(id+'v').innerHTML=(Fs[i]/1000).toFixed(2)+'<span class="mc-u">kN</span>';ge(id+'s').textContent=descs[i];ge(id).className='mc '+(isL?'danger':'');ge(id).style.opacity='1';});
777	  ge('bd4v').textContent=r.failMode;ge('bd4').className='mc '+(r.failMode==='ボルト破断'?'ok':'danger');
778	  const bkL=['ボルト破断','山飛び','座面A','座面B'],lims=Fs.map(f=>f/1000),reqs=lims.map(v=>Math.min(v,r.Flim/1000)/sf);
779	  mkC('cMG',{type:'bar',data:{labels:bkL,datasets:[{label:'限界軸力',data:lims,backgroundColor:lims.map((v,i)=>Math.abs(v-r.Flim/1000)<0.01?'#E24B4A':'#85B7EB'),borderWidth:0},{label:'要求(/S)',data:reqs,backgroundColor:'#C0DD97',borderWidth:0}]},options:{responsive:true,maintainAspectRatio:false,animation:{duration:200},layout:{padding:{right:10}},plugins:{legend:{display:false}},scales:{x:{ticks:{font:{size:9}}},y:{title:{display:true,text:'軸力 (kN)',font:{size:9}},ticks:{font:{size:9}},grace:'5%'}}}});
780	  const bkLL=['ボルト破断',`山飛び（${r.hasNut?'ナット':'部材B'}）`,'座面陥没 A面','座面陥没 B面'];
781	  const recTorque=r.T_lim?r.T_lim/sf:null;
782	  ge('bd-tbl').innerHTML=bkLL.map((l,i)=>{
783	    const isL=Math.abs(Fs[i]-r.Flim)<0.01;
784	    const mg=(Fs[i]/1000)/(r.Flim/1000/sf);
785	    const tl=Fs[i]*r.denom;
786	    const isDanger=recTorque&&tl<recTorque;
787	    const torqueStyle=isDanger?'color:#E24B4A;font-weight:bold':isL?'color:#E24B4A;font-weight:bold':'';
788	    const rowStyle=isL?'background:#FFF5F5':'';
789	    return `<tr style="${rowStyle}"><td style="${isL?'font-weight:bold':''}"><span style="margin-right:4px">${isL?'⚠':''}</span>${l}</td><td>${(Fs[i]/1000).toFixed(2)}</td><td style="${torqueStyle}">${tl.toFixed(1)}${isDanger?' ⚠':''}</td><td style="${mg<1.2?'color:#A32D2D':mg<1.5?'color:#854F0B':'color:#3B6D11'}">${mg.toFixed(2)}x</td><td>${isL?'<span class="sb2 s-l">支配的</span>':'—'}</td></tr>`;
790	  }).join('');
791	}
792	function buildJoint(r,sf,fext){
793	  const s=r.stiff;
794	  ge('jt-kb').textContent=(s.kb/1000).toFixed(0)+' kN/mm';ge('jt-kc').textContent=(s.kc/1000).toFixed(0)+' kN/mm';ge('jt-phi').textContent=s.phi.toFixed(4);
795	  const Fi=r.T_lim?(r.T_lim/sf)/r.denom*1000:r.Flim/sf,half=Math.abs(fext)||Fi*0.5,Fext_range=Array.from({length:21},(_,i)=>(i-10)*half/10);
796	  mkC('cJT',{type:'line',data:{datasets:[{label:'ボルト軸力',data:Fext_range.map(fe=>({x:fe/1000,y:(Fi+s.phi*fe)/1000})),borderColor:'#185FA5',backgroundColor:'transparent',borderWidth:2,pointRadius:0},{label:'残留締付力',data:Fext_range.map(fe=>({x:fe/1000,y:Math.max(0,(Fi-(1-s.phi)*fe)/1000)})),borderColor:'#1D9E75',backgroundColor:'transparent',borderWidth:2,pointRadius:0,borderDash:[4,2]},{label:'初期Fi',data:[{x:Fext_range[0]/1000,y:Fi/1000},{x:Fext_range[20]/1000,y:Fi/1000}],borderColor:'#888',backgroundColor:'transparent',borderWidth:1,pointRadius:0,borderDash:[3,3]}]},options:{responsive:true,maintainAspectRatio:false,animation:{duration:200},layout:{padding:{right:10}},plugins:{legend:{display:false}},scales:{x:{type:'linear',title:{display:true,text:'外部軸力 Fext (kN)',font:{size:9}},ticks:{font:{size:9}},grace:'5%'},y:{title:{display:true,text:'軸力 (kN)',font:{size:9}},ticks:{font:{size:9}},grace:'5%'}}}});
797	  const phiArr=Array.from({length:21},(_,i)=>+(i*0.05).toFixed(2));
798	  mkC('cPH',{type:'line',data:{datasets:[{label:'ボルト負担',data:phiArr.map(p=>({x:p,y:p})),borderColor:'#185FA5',backgroundColor:'transparent',borderWidth:2,pointRadius:0},{label:'部材負担',data:phiArr.map(p=>({x:p,y:1-p})),borderColor:'#1D9E75',backgroundColor:'transparent',borderWidth:2,pointRadius:0,borderDash:[4,2]},{label:'現在Φ',data:[{x:s.phi,y:0},{x:s.phi,y:1}],borderColor:'#E24B4A',backgroundColor:'transparent',borderWidth:1.5,pointRadius:0,borderDash:[3,3]}]},options:{responsive:true,maintainAspectRatio:false,animation:{duration:200},layout:{padding:{right:10}},plugins:{legend:{display:false}},scales:{x:{type:'linear',min:0,max:1,title:{display:true,text:'剛性比 Φ',font:{size:9}},ticks:{font:{size:9}}},y:{min:0,max:1,title:{display:true,text:'外力分担割合',font:{size:9}},ticks:{font:{size:9}}}}}});
799	  ge('jt-tbl').innerHTML=[
800	    ['初期締付力 Fi',`${(Fi/1000).toFixed(2)} kN`,`推奨T ${r.T_lim?(r.T_lim/sf).toFixed(1):'—'} Nm 締付時`],
801	    ['ボルト剛性 kb',`${(s.kb/1000).toFixed(0)} kN/mm`,`E=${r.Eb} GPa, As=${r.b.As} mm², Lg=${r.Lg} mm`],
802	    ['被締結部材 A 剛性',`${(s.kca/1000).toFixed(0)} kN/mm`,`${CL_MAT[r.cmA].name}, t=${r.tA} mm`],
803	    ['被締結部材 B 剛性',`${(s.kcb/1000).toFixed(0)} kN/mm`,`${CL_MAT[r.cmB].name}, t=${r.tB} mm`],
804	    ['合成部材剛性 kc',`${(s.kc/1000).toFixed(0)} kN/mm`,'1/(1/kca + 1/kcb)'],
805	    ['剛性比 Φ',s.phi.toFixed(4),'Φ < 0.1 が推奨'],
806	    ['外部軸力のΔFb',`${(s.phi*(fext||0)/1000).toFixed(2)} kN`,`Fext = ${fext} N`],
807	    ['残留締付力',`${Math.max(0,(Fi-(1-s.phi)*(fext||0))/1000).toFixed(2)} kN`,'0以上を確認（開口防止）']
808	  ].map(([a,b,c])=>`<tr><td>${a}</td><td>${b}</td><td style="color:#888">${c}</td></tr>`).join('');
809	}
810	function switchTab(name){
811	  curTab=name;
812	  ['graph','table','breakdown','joint','fatigue'].forEach(n=>{ge('tab-'+n).className='tab'+(n===name?' on':'');ge('pane-'+n).style.display=n===name?'':'none';});
813	  const sf=+gv('safety'),fext=+gv('f_ext');
814	  if(name==='graph')drawGraphs(RES,RES2,sf);
815	  else if(name==='table')buildTable(RES);
816	  else if(name==='breakdown')buildBreakdown(RES,sf);
817	  else if(name==='joint')buildJoint(RES,sf,fext);
818	  else buildFatigue(RES,sf);
819	}
820	function toggleCmp(){ge('caseb').style.display=ge('cmp_on').checked?'':'none';calc()}
821	function exportCSV(){if(!RES)return;let s='\uFEFFT(Nm),F(N),σ(MPa),τ(MPa),σeq(MPa),利用率(%),状態\n';RES.rows.forEach(r=>s+=`${r.T},${(r.F*1000).toFixed(0)},${r.sig},${r.tau},${r.seq},${r.util},${r.over?'限界超':r.plastic?'塑性域':'弾性域'}\n`);const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([s],{type:'text/csv;charset=utf-8'}));a.download=`bolt_M${RES.d}_${RES.grK}.csv`;a.click()}
822	function exportXLSX(){if(!RES||typeof XLSX==='undefined')return;const r=RES,sf=+gv('safety'),wb=XLSX.utils.book_new(),s=r.stiff,fi=r.T_lim?(r.T_lim/sf)/r.denom*1000:r.Flim/sf;const sum=[['項目','値'],['ボルト径',`M${r.d}`],['強度区分',r.grK],['E(GPa)',r.Eb],['Lg(mm)',r.Lg],['μt',r.mu_t],['μw',r.mu_w],['めねじ材',r.nut.name],['ねじ込み',`${r.dep}D`],['被締結材A',CL_MAT[r.cmA].name],['tA(mm)',r.tA],['面圧A(MPa)',r.bA],['被締結材B',CL_MAT[r.cmB].name],['tB(mm)',r.tB],['面圧B(MPa)',r.bB],['安全率',sf],[' ',' '],['限界軸力(kN)',(r.Flim/1000).toFixed(3)],['ボルト破断(kN)',(r.Fbrk/1000).toFixed(3)],['山飛り(kN)',(r.Fstr/1000).toFixed(3)],['座面A(kN)',(r.FbA/1000).toFixed(3)],['座面B(kN)',(r.FbB/1000).toFixed(3)],['限界T(Nm)',r.T_lim?r.T_lim.toFixed(2):'—'],['降伏T(Nm)',r.T_yld?r.T_yld.toFixed(2):'—'],['推奨T(Nm)',r.T_lim?(r.T_lim/sf).toFixed(2):'—'],['破損モード',r.failMode],[' ',' '],['kb(N/mm)',s.kb.toFixed(0)],['kc(N/mm)',s.kc.toFixed(0)],['Φ',s.phi.toFixed(4)],['Fi(kN)',(fi/1000).toFixed(3)]];XLSX.utils.book_append_sheet(wb,XLSX.utils.aoa_to_sheet(sum),'解析サマリ');const data=[['T(Nm)','F(N)','σ(MPa)','τ(MPa)','σeq(MPa)','利用率(%)','状態']];RES.rows.forEach(row=>data.push([row.T,(row.F*1000).toFixed(0),row.sig,row.tau,row.seq,row.util,row.over?'限界超':row.plastic?'塑性域':'弾性域']));XLSX.utils.book_append_sheet(wb,XLSX.utils.aoa_to_sheet(data),'全生データ');XLSX.writeFile(wb,`bolt_M${r.d}_${r.grK}.xlsx`)}
