    const lf=(A.rows.find(r=>r.T>=A.T_lim)?.F||A.rows[A.rows.length-1].F)*1.1;
    ds.push({label:'限界T',data:[{x:A.T_lim,y:0},{x:A.T_lim,y:lf}],borderColor:'#E24B4A',backgroundColor:'transparent',borderWidth:1.5,pointRadius:0,borderDash:[5,5]});
    lineLabels.push({value:A.T_lim,label:`限界トルク: ${A.T_lim.toFixed(1)} Nm`,color:'#E24B4A',font:'bold 11px sans-serif'});
  }
  const opts={responsive:true,maintainAspectRatio:false,animation:{duration:200},layout:{padding:{right:10,top:20}},plugins:{legend:{display:false},tooltip:{callbacks:{title:i=>`T = ${parseFloat(i[0].raw.x).toFixed(1)} Nm`,label:i=>`${i.dataset.label}: F = ${(parseFloat(i.raw.y)*1000).toFixed(0)} N`}},verticalLineLabels:{lines:lineLabels}},scales:{x:{type:'linear',title:{display:true,text:'締め付けトルク T (Nm)',font:{size:10}},ticks:{font:{size:9}},grace:'5%'},y:{title:{display:true,text:'軸力 F (kN)',font:{size:10}},ticks:{font:{size:9},callback:v=>v.toFixed(2)},grace:'5%'}}};
  mkC('cTF',{type:'line',data:{datasets:ds},options:opts});
  ge('leg-tf').innerHTML=[{c:'#185FA5',l:'弾性域(A)'},{c:'#EF9F27',l:'塑性域(A)'},{c:lc,l:'限界(A)',d:true},{c:'#E24B4A',l:'限界T',d:true},{c:'#639922',l:'推奨T',d:true},...(B?[{c:'#D85A30',l:'弾性域(B)',d2:true},{c:'#993C1D',l:'塑性域(B)',d2:true}]:[])].map(i=>`<span class="li"><span class="ls" style="background:${i.d||i.d2?'transparent':i.c};${i.d?'border-top:2px dashed '+i.c:i.d2?'border-top:2px dotted '+i.c:''}"></span>${i.l}</span>`).join('');
  const maxSeqRow=A.rows.reduce((max,r)=>r.seq>max.seq?r:max,A.rows[0]);
  const maxSeq=maxSeqRow.seq;
  const maxSeqTorque=maxSeqRow.T;
  const safetyFactor=A.gr.Sy/maxSeq;
  const isSafe=safetyFactor>=1.0;
  const stDs=[{label:'等価応力（算出値）',data:A.rows.map(r=>({x:r.T,y:r.seq})),borderColor:'#3B5AB7',backgroundColor:'transparent',borderWidth:2.5,pointRadius:0,tension:0.2},{label:'降伏応力（許容限界）',data:[{x:0,y:A.gr.Sy},{x:A.rows[A.rows.length-1].T,y:A.gr.Sy}],borderColor:'#FFD700',backgroundColor:'transparent',borderWidth:2,pointRadius:0,borderDash:[6,4]},{label:'引張強さ（破断限界）',data:[{x:0,y:A.gr.Su},{x:A.rows[A.rows.length-1].T,y:A.gr.Su}],borderColor:'#FF3B30',backgroundColor:'transparent',borderWidth:2,pointRadius:0,borderDash:[6,4]}];
