  mkC('cST',{type:'line',data:{datasets:stDs},options:stOpts});
  ge('leg-st').innerHTML=[{c:'#3B5AB7',l:'等価応力（算出値）',solid:true},{c:'#FFD700',l:'降伏応力（許容限界）',dash:true},{c:'#FF3B30',l:'引張強さ（破断限界）',dash:true}].map(i=>`<span class="li"><span class="ls" style="background:${i.solid?i.c:'transparent'};${i.dash?'border-top:2px dashed '+i.c:''}"></span>${i.l}</span>`).join('');
  ge('safety-factor-display').innerHTML=`<strong>安全率 S = ${safetyFactor.toFixed(2)}</strong> <span style="color:#666;font-size:9px">（トルク T = ${maxSeqTorque.toFixed(1)} Nm 時）</span><br>${isSafe?'<span style="color:#3B6D11">✓ 安全</span>':'<span style="color:#E24B4A">⚠ 危険（塑性変形リスク）</span>'}`;
  ge('safety-factor-display').style.backgroundColor=isSafe?'#EAF3DE':'#FCEBEB';
  ge('safety-factor-display').style.borderLeft=isSafe?'3px solid #639922':'3px solid #E24B4A';
  const bkL=['ボルト破断','山飛び','座面A','座面B'],bkV=[A.Fbrk/1000,A.Fstr/1000,A.FbA/1000,A.FbB/1000];
  const bkT=[A.Fbrk*A.denom,A.Fstr*A.denom,A.FbA*A.denom,A.FbB*A.denom];
  const bkLabels=bkL.map((label,i)=>[label,`${bkT[i].toFixed(1)} Nm`]);
  mkC('cBK',{type:'bar',data:{labels:bkLabels,datasets:[{data:bkV,backgroundColor:bkV.map(v=>Math.abs(v-A.Flim/1000)<0.01?'#E24B4A':'#85B7EB'),borderWidth:0}]},options:{responsive:true,maintainAspectRatio:false,animation:{duration:200},layout:{padding:{right:10}},plugins:{legend:{display:false},tooltip:{callbacks:{label:i=>`${parseFloat(i.raw).toFixed(2)} kN`}}},scales:{x:{ticks:{font:{size:9}}},y:{title:{display:true,text:'軸力 (kN)',font:{size:9}},ticks:{font:{size:9},callback:v=>v.toFixed(2)},grace:'5%'}}}});

