const isSafe=safetyFactor>=1.0;
const stDs=[{label:'等価応力 (A)',data:A.rows.map(r=>({x:r.T,y:r.seq})),borderColor:'#3B5AB7',backgroundColor:'transparent',borderWidth:2.5,pointRadius:0,tension:0.2},{label:'降伏応力 (A)',data:[{x:0,y:A.gr.Sy},{x:A.rows[A.rows.length-1].T,y:A.gr.Sy}],borderColor:'#FFD700',backgroundColor:'transparent',borderWidth:2,pointRadius:0,borderDash:[6,4]},{label:'引張強さ (A)',data:[{x:0,y:A.gr.Su},{x:A.rows[A.rows.length-1].T,y:A.gr.Su}],borderColor:'#FF3B30',backgroundColor:'transparent',borderWidth:2,pointRadius:0,borderDash:[6,4]}];
if(B){
  stDs.push({label:'等価応力 (B)',data:B.rows.map(r=>({x:r.T,y:r.seq})),borderColor:'#D85A30',backgroundColor:'transparent',borderWidth:2.5,pointRadius:0,tension:0.2,borderDash:[4,2]});
  stDs.push({label:'降伏応力 (B)',data:[{x:0,y:B.gr.Sy},{x:B.rows[B.rows.length-1].T,y:B.gr.Sy}],borderColor:'#FFB700',backgroundColor:'transparent',borderWidth:2,pointRadius:0,borderDash:[2,2]});
  stDs.push({label:'引張強さ (B)',data:[{x:0,y:B.gr.Su},{x:B.rows[B.rows.length-1].T,y:B.gr.Su}],borderColor:'#FF6B4A',backgroundColor:'transparent',borderWidth:2,pointRadius:0,borderDash:[2,2]});
}
const stLineLabels=[];
if(A.T_lim){
  const rt=A.T_lim/sf,maxY=Math.max(A.gr.Su,B?Math.max(B.gr.Su,maxSeq):maxSeq)*1.1;
  stDs.push({label:'推奨T (A)',data:[{x:rt,y:0},{x:rt,y:maxY}],borderColor:'#639922',backgroundColor:'transparent',borderWidth:2,pointRadius:0,borderDash:[3,3]});
  stLineLabels.push({value:rt,label:`推奨T(A): ${rt.toFixed(1)} Nm`,color:'#639922',font:'bold 11px sans-serif'});
  stDs.push({label:'限界T (A)',data:[{x:A.T_lim,y:0},{x:A.T_lim,y:maxY}],borderColor:'#E24B4A',backgroundColor:'transparent',borderWidth:2,pointRadius:0,borderDash:[5,5]});
  stLineLabels.push({value:A.T_lim,label:`限界T(A): ${A.T_lim.toFixed(1)} Nm`,color:'#E24B4A',font:'bold 11px sans-serif'});
}
if(B&&B.T_lim){
  const rtB=B.T_lim/sf,maxY=Math.max(A.gr.Su,B.gr.Su,maxSeq)*1.1;
  stDs.push({label:'推奨T (B)',data:[{x:rtB,y:0},{x:rtB,y:maxY}],borderColor:'#8AB661',backgroundColor:'transparent',borderWidth:2,pointRadius:0,borderDash:[3,3]});
  stLineLabels.push({value:rtB,label:`推奨T(B): ${rtB.toFixed(1)} Nm`,color:'#8AB661',font:'bold 11px sans-serif'});
  stDs.push({label:'限界T (B)',data:[{x:B.T_lim,y:0},{x:B.T_lim,y:maxY}],borderColor:'#FF6B4A',backgroundColor:'transparent',borderWidth:2,pointRadius:0,borderDash:[5,5]});
  stLineLabels.push({value:B.T_lim,label:`限界T(B): ${B.T_lim.toFixed(1)} Nm`,color:'#FF6B4A',font:'bold 11px sans-serif'});
}
const stOpts={responsive:true,maintainAspectRatio:false,animation:{duration:200},layout:{padding:{right:10,top:20}},plugins:{legend:{display:true,position:'top',labels:{font:{size:10},padding:8,usePointStyle:true}},tooltip:{callbacks:{title:i=>`締付トルク T = ${parseFloat(i[0].raw.x).toFixed(1)} Nm`,label:function(ctx){const val=parseFloat(ctx.raw.y).toFixed(1);if(ctx.dataset.label.includes('等価応力')){const row=A.rows.find(r=>Math.abs(r.T-ctx.raw.x)<0.01);if(row)return[`${ctx.dataset.label}: ${val} MPa`,`計算式: √(σ²+3τ²)`,`利用率: ${row.util.toFixed(1)}%`];return `${ctx.dataset.label}: ${val} MPa`;}return `${ctx.dataset.label}: ${val} MPa`;},afterLabel:function(ctx){if(ctx.dataset.label.includes('降伏'))return '塑性域に入る限界';if(ctx.dataset.label.includes('引張'))return 'ボルト破断の限界';return null;}},backgroundColor:'rgba(0,0,0,0.85)',titleFont:{size:11,weight:'bold'},bodyFont:{size:10},padding:10},verticalLineLabels:{lines:stLineLabels}},scales:{x:{type:'linear',title:{display:true,text:'締め付けトルク T (Nm)',font:{size:10}},ticks:{font:{size:9}},grace:'5%'},y:{title:{display:true,text:'応力 (MPa)',font:{size:10}},ticks:{font:{size:9}},grace:'5%'}}};
mkC('cST',{type:'line',data:{datasets:stDs},options:stOpts});
ge('leg-st').innerHTML=[{c:'#3B5AB7',l:'等価応力（算出値）',solid:true},{c:'#FFD700',l:'降伏応力（許容限界）',dash:true},{c:'#FF3B30',l:'引張強さ（破断限界）',dash:true}].map(i=>`<span class="li"><span class="ls" style="background:${i.solid?i.c:'transparent'};${i.dash?'border-top:2px dashed '+i.c:''}"></span>${i.l}</span>`).join('');

